class Solution:
    def largestEven(self, s):
        # Independent construction: strip trailing '1' characters one at a time
        # from the right instead of locating the last '2' via search, to catch
        # an off-by-one in the index-based solution.
        t = s
        while t and t[-1] == '1':
            t = t[:-1]
        return t

